class Solution {
public:
    vector<int> maxDepthAfterSplit(string seq) {
        vector<int> res;
        int depth = 0, last = 0;
        for (char c : seq) {
            if (c == '(') {
                depth++;
                last = 0;
            } else {
                depth--;
                last = 1;
            }
            res.push_back(last);
        }
        return res;
    }
};
```
